.editor-word-count {
    font-size: 0.8rem;
    color: var(--text-muted);
    user-select: none;
    padding-left: 0.25rem;
}

/* ── Bar loader positioning ── */
.editor-loader-wrapper {
    height: 4px;
    flex-shrink: 0;
}

/* ── Save button ── */
.editor-save-bttn {
    display: flex;
    justify-content: center;
    align-items: center;
    padding: 0.5rem 1.25rem;
    border-radius: 15px;
    background-color: var(--editor-accent);
    color: #ffffff;
    font-weight: 650;
    cursor: pointer;
    border: none;
    transition: background-color 0.15s ease, transform 0.1s ease, opacity 0.15s ease;
}
.editor-save-bttn:hover {
    opacity: 0.9;
}
.editor-save-bttn:active {
    transform: scale(0.98);
}
.editor-save-bttn:focus {
    outline: none;
}
.editor-save-bttn-disabled {
    display: flex;
    justify-content: center;
    align-items: center;
    padding: 0.5rem 1.25rem;
    border-radius: 15px;
    background-color: var(--bg-pill);
    color: var(--text-muted);
    font-weight: 650;
    user-select: none;
    border: none;
    cursor: not-allowed;
}
.editor-save-bttn-disabled:focus {
    outline: none;
}

/* ── Image upload icon (inside toolbar) ── */
.editor-upload-image-icon {
    padding: 0.4rem;
    border-radius: 6px;
    cursor: pointer;
    transition: all 0.15s ease;
}
.editor-upload-image-icon:hover {
    background-color: var(--bg-pill);
}

/* ── Image components ── */
.image-container {
    display: flex;
    justify-content: center;
    width: 100%;
    height: fit-content;
}
.image-wrapper {
    position: relative;
