        getNextPageParam: (lastPage) => {
            if(lastPage.hasMore){
                const lastJournal = lastPage?.data[lastPage?.data?.length - 1];
                return new Date(lastJournal.created_at).toISOString();
            } else {
                return undefined;
            }
        },
        enabled: !!session,
        refetchOnWindowFocus: false,
        staleTime: 1000 * 60 * 2
    })

    useEffect(() => {
        if(inView && !isFetchinNextPage && hasNextPage){
            fetchNextPage();
        }
    }, [fetchNextPage, hasNextPage, isFetchinNextPage, inView])

