                                        </div>
                                        </>
                                    )}
                                </div>
                            </div>
                        </div>

                    </div>
                )
            })}
            <div ref={inviewRef} className="notification-inview-container">
                {isFetchinNextPage && (
                    <MoonLoader loading={isFetchinNextPage} color="var(--loader-color)" size={20}/>
                )}
            </div>
        </div>
        </>
    )
}

